100→+    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
101→+                                       String targetSpaceId, String sourceSpaceId,
102→+                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
103→+        // 文件夹没有版本快照
104→+        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
105→+            return;
106→+        }
107→+
108→+        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
109→+                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
110→+        if (snapshots.isEmpty()) {
111→+            return;
112→+        }
113→+
114→+        log.info("copyVersionSnapshots: originalNodeId={}, newNodeId={}, snapshotCount={}",
115→+                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());
116→+
117→+        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
118→+            try {
119→+                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
120→+                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
121→+                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
122→+                snapshotNodeVo.setName(snapshot.getSnapshotName());
123→+
124→+                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
125→+                snapshotTreeNode.setData(snapshotNodeVo);
126→+
127→+                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
128→+                snapshotTree.add(snapshotTreeNode);
129→+
130→+                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
131→+                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);
132→+
133→+                if (result.getErrorMessage() != null) {
134→+                    log.warn("copyVersionSnapshots: failed to copy snapshot file, originalNodeId={}, snapshotId={}, error={}",
135→+                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
136→+                    continue;
137→+                }
138→+
139→+                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
140→+                if (newSnapshotFileId == null) {
141→+                    log.warn("copyVersionSnapshots: no mapping for snapshotId={}", snapshot.getSnapshotId());
142→+                    continue;
143→+                }
144→+
145→+                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
146→+                        .nodeId(newSpaceNodeEntity.getId())
147→+                        .snapshotId(newSnapshotFileId)
148→+                        .snapshotName(snapshot.getSnapshotName())
149→+                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
150→+                        .operatorId(0L)
151→+                        .build();
152→+                versionSnapshotService.save(newSnapshot);
153→+
154→+                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
155→+                        .appSpaceNodeId(newSnapshotFileId)
156→+                        .name(snapshot.getSnapshotName())
157→+                        .type(newSpaceNodeEntity.getType())
158→+                        .description("")
159→+                        .spaceId(targetSpaceId)
160→+                        .createdBy(newSpaceNodeEntity.getCreatedBy())
161→+                        .updatedBy(newSpaceNodeEntity.getUpdatedBy())
162→+                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
163→+                        .build();
164→+                spaceNodeService.save(snapshotSpaceNode);
165→+
166→+                log.info("copyVersionSnapshots: copied snapshot, originalSnapshotId={}, newSnapshotId={}, newNodeId={}",
167→+                        snapshot.getSnapshotId(), newSnapshotFileId, newSpaceNodeEntity.getId());
168→+
169→+            } catch (Exception e) {
170→+                log.error("copyVersionSnapshots: failed to copy snapshot, originalNodeId={}, snapshotId={}, error={}",
171→+                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
172→             }
173→         }
174→     }
