215→        if (newNodeId == null) {
216→            log.error("No mapping found for node: {}", oldNodeId);
217→            return;
218→        }
219→

200→        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
201→        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(sourceSpaceId);
202→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
