232→        List<String> appSpaceNodeIds =  overallResult.getNodeIdMapping().values().stream().toList();
233→        List<SpaceNodeEntity> spaceNodeEntityList = spaceNodeQueryManager.getSpaceNodeByAppIds(appSpaceNodeIds);
